/**
 * Fable Spend Consent — PreToolUse[Agent] hook (inside sync-task-dispatcher)
 *
 * Claude Fable 5 bills at $10/$50 per MTok — 2x Opus output pricing. Spawning
 * agents pinned to it is a deliberate spend decision, not a default: this
 * gate escalates any explicit fable model pin on an Agent/Task spawn to a
 * user permission prompt (outputAsk), so the spend is consented per-spawn.
 *
 * Opt-in bypass: set ORK_FABLE_OK=1 to pre-consent for the session/CI run.
 * Sessions whose MAIN model is fable are untouched — choosing the session
 * model is already the user's own deliberate act, and `inherit` agents
 * follow it without re-prompting (the model-cost-advisor separately warns
 * when inherited-fable runs low/medium-complexity tasks).
 *
 * @hook PreToolUse[Agent] via sync-task-dispatcher
 */

import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, outputAsk } from '../../lib/common.js';
import { NOOP_CTX } from '../../lib/context.js';

const HOOK_NAME = 'fable-spend-consent';

/** Explicit fable pins, short or full ID (covers claude-fable-5[1m] too). */
function isFablePin(model: string): boolean {
  return model === 'fable' || model.startsWith('claude-fable');
}

export function fableSpendConsent(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const toolInput = input.tool_input || {};
  const model = (toolInput.model as string) || '';

  if (!model || !isFablePin(model)) {
    return outputSilentSuccess();
  }

  if (process.env.ORK_FABLE_OK === '1') {
    ctx.log(HOOK_NAME, `fable pin allowed (ORK_FABLE_OK=1): ${model}`);
    return outputSilentSuccess();
  }

  ctx.log(HOOK_NAME, `escalating fable pin to user consent: ${model}`);
  return outputAsk(
    `This agent spawn pins model "${model}" — Claude Fable 5 bills $10/$50 per MTok ` +
    `(2x Opus output pricing). Approve to spend deliberately, or deny and re-spawn ` +
    `with model "inherit"/"sonnet". Pre-consent for this session with ORK_FABLE_OK=1.`,
  );
}
